#!/usr/bin/env python3
from __future__ import annotations

import json
import re
from collections import Counter
from datetime import datetime, timedelta
from pathlib import Path

WORKSPACE = Path('/Users/ling/.openclaw/workspace')
MEMORY_DIR = WORKSPACE / 'memory'
LEARNINGS = WORKSPACE / '.learnings' / 'LEARNINGS.md'
LOG_DIR = WORKSPACE / 'logs'
DISTILL_DIR = MEMORY_DIR / 'nightly_distill'
RULES_DIR = MEMORY_DIR / 'nightly_rules'
STATE_PATH = MEMORY_DIR / 'nightly_memory_job_state.json'

RULE_PATTERNS = [
    r'默认[^。；\n]{0,80}',
    r'必须[^。；\n]{0,80}',
    r'不要[^。；\n]{0,80}',
    r'仅在[^。；\n]{0,80}',
    r'后面[^。；\n]{0,80}',
]


def now_cn() -> datetime:
    return datetime.now()


def read_text(path: Path) -> str:
    if not path.exists():
        return ''
    return path.read_text(encoding='utf-8', errors='ignore')


def extract_candidates(text: str) -> list[str]:
    candidates: list[str] = []
    for pat in RULE_PATTERNS:
        for m in re.findall(pat, text):
            item = m.strip(' -：:')
            if len(item) >= 6:
                candidates.append(item)
    deduped = []
    seen = set()
    for c in candidates:
        if c not in seen:
            seen.add(c)
            deduped.append(c)
    return deduped[:20]


def cleanup_low_value() -> list[str]:
    removed: list[str] = []
    cutoff = now_cn() - timedelta(days=2)
    for p in MEMORY_DIR.glob('_*.txt'):
        try:
            if datetime.fromtimestamp(p.stat().st_mtime) < cutoff:
                p.unlink(missing_ok=True)
                removed.append(str(p))
        except Exception:
            continue
    return removed


def main() -> int:
    started_at = now_cn()
    date_tag = started_at.strftime('%Y-%m-%d')
    memory_today = MEMORY_DIR / f'{date_tag}.md'
    memory_text = read_text(memory_today)
    learnings_text = read_text(LEARNINGS)
    learnings_tail = '\n'.join(learnings_text.splitlines()[-120:]) if learnings_text else ''

    source_text = '\n'.join([memory_text, learnings_tail]).strip()
    line_count = len([x for x in source_text.splitlines() if x.strip()])
    candidates = extract_candidates(source_text)

    keyword_counter = Counter()
    for kw in ['量化', '飞书', '面板', '模拟盘', '规则', '自动', '中文', '持仓', '报告', '夜跑']:
        keyword_counter[kw] = source_text.count(kw)

    DISTILL_DIR.mkdir(parents=True, exist_ok=True)
    RULES_DIR.mkdir(parents=True, exist_ok=True)
    LOG_DIR.mkdir(parents=True, exist_ok=True)

    distill_path = DISTILL_DIR / f'{date_tag}.md'
    rules_path = RULES_DIR / f'{date_tag}.md'

    distill_md = f'''# 夜跑提炼 {date_tag}

- started_at: {started_at.strftime('%Y-%m-%d %H:%M:%S')}
- source_memory: `{memory_today}`
- source_learnings: `{LEARNINGS}`
- source_nonempty_lines: {line_count}

## 高频主题
'''
    for k, v in keyword_counter.items():
        distill_md += f'- {k}: {v}\n'
    distill_md += '\n## 今日提炼\n'
    if source_text:
        bullets = [x.strip() for x in source_text.splitlines() if x.strip().startswith('- ')]
        for b in bullets[:20]:
            distill_md += f'{b}\n'
    else:
        distill_md += '- 今日暂无可提炼内容\n'

    rules_md = f'''# 夜跑规则候选 {date_tag}

- started_at: {started_at.strftime('%Y-%m-%d %H:%M:%S')}
- candidate_count: {len(candidates)}

## 规则候选
'''
    if candidates:
        for item in candidates:
            rules_md += f'- {item}\n'
    else:
        rules_md += '- 今日未抽取到稳定规则候选\n'

    distill_path.write_text(distill_md, encoding='utf-8')
    rules_path.write_text(rules_md, encoding='utf-8')
    removed = cleanup_low_value()

    finished_at = now_cn()
    state = {
        'task': 'nightly_memory_distill',
        'started_at': started_at.strftime('%Y-%m-%d %H:%M:%S'),
        'finished_at': finished_at.strftime('%Y-%m-%d %H:%M:%S'),
        'status': 'OK',
        'memory_today': str(memory_today),
        'distill_path': str(distill_path),
        'rules_path': str(rules_path),
        'cleanup_removed': removed,
        'candidate_count': len(candidates),
    }
    STATE_PATH.write_text(json.dumps(state, ensure_ascii=False, indent=2) + '\n', encoding='utf-8')
    print(json.dumps(state, ensure_ascii=False, indent=2))
    return 0


if __name__ == '__main__':
    raise SystemExit(main())
